void RegisterTextScroller(FSketchModule& Host)
{
	using namespace sketch;
	FFactory Factory;
	Factory.Name = TEXT("TextScroller");
	Factory.ConstructWidget = []
		{
			TSharedRef<HeaderTool::FUniqueSlotMeta> Meta = MakeShared<HeaderTool::FUniqueSlotMeta>();
			Meta->Slots.Reserve(1);
			STextScroller::FArguments Arguments;
			Arguments
				// .ScrollOptions(Sketch("ScrollOptions", FTextScrollerOptions(  )))
				// .ScrollOrientation(Sketch("ScrollOrientation", EOrientation( Orient_Horizontal )))
				.Content()[SAssignNew(Meta->Slots.Emplace(FName(TEXT("Content"))), SSketchWidget).SetupAsUniqueSlotContainer(TEXT("Content"))]
				.AddMetaData(MoveTemp(Meta))
				.SKETCH_WIDGET_FACTORY_BOILERPLATE();
			TSharedRef<STextScroller> Widget = SArgumentNew(Arguments, STextScroller);
			return MoveTemp(Widget);
		};
	Factory.EnumerateUniqueSlots = &HeaderTool::FUniqueSlotMeta::GetSlots;
	Host.RegisterFactory(TEXT("Text"), MoveTemp(Factory));
}


